import requests

KEY = 'PKJTQ4OXEGBIHHRJJ7GXHK3KRC'
SEC = 'xKx6GRNUGoppgWLsNqhYGe6LGsn0pGHKwP1h6Mctc'

# Check if crypto trading is enabled on our account
for endpoint in [
    '/v2/account',
    '/v2/crypto/accounts',
    '/v1beta1/crypto/accounts',
    '/v2/assets?status=active',
]:
    try:
        r = requests.get(f'https://paper-api.alpaca.markets{endpoint}',
            headers={'APCA-API-KEY-ID': KEY, 'APCA-API-SECRET-KEY': SEC}, timeout=8)
        print(f"{endpoint}: {r.status_code}")
        if r.status_code == 200:
            data = r.json()
            if isinstance(data, list):
                crypto = [a for a in data if a.get('class') == 'crypto' or 'crypto' in str(a).lower()]
                print(f"  → {len(data)} assets, {len(crypto)} crypto")
                if crypto[:2]: print(f"  crypto samples: {crypto[:2]}")
            else:
                print(f"  → {str(data)[:200]}")
        else:
            print(f"  → {r.text[:150]}")
    except Exception as e:
        print(f"{endpoint}: ERR {e}")
